from itertools import combinations

class Solution:
    def maximizeSquareHoleArea(self, n, m, hBars, vBars):
        def best_gap(bars, total_len):
            best = 0
            for r in range(len(bars) + 1):
                for removed in combinations(bars, r):
                    remaining = sorted(set(range(1, total_len + 3)) - set(removed))
                    for i in range(1, len(remaining)):
                        best = max(best, remaining[i] - remaining[i - 1])
            return best

        max_h = best_gap(hBars, n)
        max_v = best_gap(vBars, m)
        side = min(max_h, max_v)
        return side * side

