class Solution:
    def maximizeSquareHoleArea(self, n, m, hBars, vBars):
        def longest_run_plus_one(bars):
            if not bars:
                return 1
            bars = sorted(bars)
            best = 1
            cur = 1
            for i in range(1, len(bars)):
                if bars[i] == bars[i - 1] + 1:
                    cur += 1
                else:
                    cur = 1
                best = max(best, cur)
            return best + 1

        max_h = longest_run_plus_one(hBars)
        max_v = longest_run_plus_one(vBars)
        side = min(max_h, max_v)
        return side * side

