var maximizeSquareHoleArea = function(n, m, hBars, vBars) {
    function longestRunPlusOne(bars) {
        if (bars.length === 0) return 1;
        const sorted = bars.slice().sort((a, b) => a - b);
        let best = 1, cur = 1;
        for (let i = 1; i < sorted.length; i++) {
            if (sorted[i] === sorted[i - 1] + 1) cur++;
            else cur = 1;
            best = Math.max(best, cur);
        }
        return best + 1;
    }
    const maxH = longestRunPlusOne(hBars);
    const maxV = longestRunPlusOne(vBars);
    const side = Math.min(maxH, maxV);
    return side * side;
};
